mapper.select:
/* isnrMapper.getExistInsrMember */
SELECT  A.CONTRACT_NUM AS contractNum
        , A.SVC_CNTR_NO AS svcCntrNo
        , A.END_DTTM AS endDttm
        , A.STAT_CD AS statCd
        , A.INSR_CD AS insrCd
FROM    MSP_INSR_MEMBER_MST A
WHERE   A.END_DTTM >= TO_CHAR(SYSDATE, 'YYYYMMDD') || '000000'

	AND A.CONTRACT_NUM = #{contractNum}


	AND A.SVC_CNTR_NO = #{svcCntrNo}


	AND A.INSR_CD = #{insrCd}

mapper.update:
/* isnrMapper.updateCanInsrMember */
UPDATE  MSP_INSR_MEMBER_MST
SET     STAT_CD = 'C'
        , END_DTTM = TO_CHAR(SYSDATE - 1, 'YYYYMMDD') || '235959'
        , RMK = #{refVal, jdbcType=VARCHAR}
        , RVISN_DTTM = SYSDATE
WHERE   CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}
AND     STAT_CD = 'A'

	AND INSR_CD = #{insrCd, jdbcType=VARCHAR}

mapper.delete:
/* isnrMapper.deletePartnerDongbu01 */
DELETE  FROM MSP_PARTNER_DONGBU_01 
WHERE   SEND_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')

DELETE  FROM MSP_PARTNER_POINT_FILE
WHERE   PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}
